/* BTItem — generic list item / row display molecule.
 * Figma: node 2056-48.
 * Shared between Vue (BTItem.vue) and React (BTItem.tsx) — one file, zero duplication.
 */

/* ── Root container ─────────────────────────────────────────────────────────── */

.bt-item {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: var(--space-sm);
}

.bt-item--outline {
  border: 1px solid var(--border-primary);
  padding: var(--space-sm);
  border-radius: var(--radius-sm);
}

.bt-item--muted {
  background: var(--bg-subtle);
  padding: var(--space-sm);
  border-radius: var(--radius-sm);
}

/* ── Left area ──────────────────────────────────────────────────────────────── */

.bt-item__left {
  display: flex;
  flex-direction: row;
  align-items: center;
  gap: var(--space-sm);
  flex: 1;
  min-width: 0;
}

.bt-item__left-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

.bt-item__left-icon > svg,
.bt-item__right-icon > svg {
  width: 16px;
  height: 16px;
  display: block;
}

/* Wrapper for any left-media element (network image, asset, SVG, etc.) */
.bt-item__media {
  flex-shrink: 0;
  width: 32px;
  height: 32px;
  border-radius: var(--radius-sm);
  overflow: hidden;          /* clips child to border-radius */
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.bt-item__media > img,
.bt-item__media > * {
  width: 100%;
  height: 100%;
  display: block;
  object-fit: cover;
}

/* ── Label stack ────────────────────────────────────────────────────────────── */

.bt-item__label {
  display: flex;
  flex-direction: column;
  gap: var(--space-2xs);
  min-width: 0;
  flex: 1;
}

.bt-item__title {
  font-size: var(--typography-font-size-sm);
  font-weight: 700;
  color: var(--text-primary);
  line-height: var(--typography-line-height-xs);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.bt-item__description {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  color: var(--text-secondary);
  line-height: var(--typography-line-height-xs);
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

/* ── Right area ─────────────────────────────────────────────────────────────── */

.bt-item__right {
  display: inline-flex;
  align-items: center;
  gap: var(--space-sm);
  flex-shrink: 0;
}

.bt-item__right-label {
  font-size: var(--typography-font-size-xs);
  font-weight: 500;
  color: var(--text-secondary);
  white-space: nowrap;
}

.bt-item__right-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: 16px;
  height: 16px;
}

/* In RTL, the right-icon (typically a navigation chevron) mirrors so the
   arrow keeps pointing toward the inline-end direction. */
[dir="rtl"] .bt-item__right-icon {
  transform: scaleX(-1);
}

/**
 * BTItem — generic list item / row display molecule.
 * Figma: node 2056-48.
 *
 * Three container variants (default / outline / muted) with optional
 * left media (icon slot, avatar, image) and optional right content
 * (label, button, icon slot).
 */
import type { BTAvatarItem } from '../avatar/BTAvatar.types';

export type BTItemType = 'default' | 'outline' | 'muted';

export interface BTItemProps {
  /** Main title text. Required. */
  title: string;
  /** Optional subtitle / description text below the title. */
  description?: string;
  /** Container style variant. @default 'default' */
  type?: BTItemType;
  /** Avatar payload — renders BTAvatar size="sm" (32px) on the left. */
  leftAvatar?: BTAvatarItem;
  /**
   * Left media element rendered at 32×32 with clipped border-radius.
   * Vue: `#leftImage` slot. React: `leftImage` ReactNode prop.
   * Flutter: `leftImage` Widget param.
   * Use any image widget — network, asset, SVG, etc.
   */
  // leftImage — slot (Vue) / ReactNode (React) / Widget (Flutter) — see each framework
  /** Right side text label (text-secondary, 12px). Ignored when rightButton is set. */
  rightLabel?: string;
  /** Right side button label — renders BTButton outline small. Takes precedence over rightLabel. */
  rightButton?: string;
}
